arguments.keystrokes:
awk '
/\/api\/v[0-9]+\/internal\// {
  if ($1 !~ /^10\./) {
    # Extract timestamp
    match($0, /\[([^\]]+)\]/, ts);
    timestamp = ts[1];

    # Convert timestamp: [05/Dec/2024:10:07:16 +0000] -> 2024-12-05T10:07:16
    cmd = "date -d \"" timestamp "\" +\"%Y-%m-%dT%H:%M:%S\" 2>/dev/null";
    cmd | getline iso_time;
    close(cmd);

    # Replace timestamp in line
    sub(/\[[^\]]+\]/, iso_time, $0);
    print $0;
  }
}' /var/log/app/access.log > /home/user/internal_hits.log

